<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    petab_sol, petab_prob; plot_type </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> :best_function</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, lw </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
